#include <stdio.h>

long factorialRecursive(int n) {
    if (n <= 1) return 1;
    return n * factorialRecursive(n - 1);
}

long factorialIterative(int n) {
    long result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

int main() {
    printf("Faktoriyel tablosu (0-10):\n");
    for (int i = 0; i <= 10; i++) {
        printf("%d! = %ld\n", i, factorialIterative(i));
    }

    printf("\nRecursive 5! = %ld\n", factorialRecursive(5));
    printf("Iteratif 5! = %ld\n", factorialIterative(5));

    // Kombinasyon hesaplama: C(n,r) = n! / (r! * (n-r)!)
    int n = 5, r = 2;
    long combination = factorialIterative(n) / (factorialIterative(r) * factorialIterative(n - r));
    printf("\nC(%d,%d) = %ld\n", n, r, combination);

    return 0;
}
